mapper.select:
SELECT h.* FROM pr_house h
WHERE h.other_code = #{otherCode}
  AND h.del_flag = 0

SELECT h.* FROM pr_house h
WHERE h.org_id = #{orgId}
  AND h.building_id = #{buildingId}
  AND h.del_flag = 0
  AND h.room_num REGEXP '^[0-9]+-[0-9]+-[0-9]+$'
ORDER BY h.seq, h.room_num

mapper.update:
UPDATE pr_house SET is_special = #{flag}, update_time = NOW() WHERE id IN
#{id}
AND del_flag = 0

UPDATE pr_house SET pay_status = #{payStatus}, is_charged = #{payStatus}, update_time = NOW() WHERE id IN
#{id}
AND del_flag = 0
